\n24\\t///     id         TEXT NOT NULL,\\n25\\t///     version    INTEGER NOT NULL,\\n26\\t///     data       TEXT NOT NULL,\\n27\\t///     PRIMARY KEY (collection, id)\\n28\\t/// );\\n29\\t/// ```\\n30\\t///\\n31\\t/// Transactions use SQLite's `BEGIN IMMEDIATE` / `COMMIT` / `ROLLBACK`\\n32\\t/// statements. `BEGIN IMMEDIATE` acquires a write lock up-front, eliminating\\n33\\t/// the TOCTOU window that exists when a read and write are issued as separate\\n34\\t/// statements.\\n35\\tpub struct SqliteStorageAdapter {\\n36\\t    conn: Mutex\u003cConnection\u003e,\\n37\\t    /// `true` while a `BEGIN` has been issued but not yet committed or rolled back.\\n38\\t    in_tx: bool,\\n39\\t}\\n40\\t\\n41\\timpl SqliteStorageAdapter {\\n42\\t    /// Opens (or creates) a SQLite database at the given path.\\n43\\t    pub fn open(path: \u0026str) -\u003e Result\u003cSelf, AxonError\u003e {\\n44\\t        let conn = Connection::open(path).map_err(|e| AxonError::Storage(e.to_string()))?;\\n45\\t        let adapter = Self {\\n46\\t            conn: Mutex::new(conn),\\n47\\t            in_tx: false,\\n48\\t        };\\n49\\t        adapter.init_schema()?;\\n50\\t        Ok(adapter)\\n51\\t    }\\n52\\t\\n53\\t    /// Opens an in-memory SQLite database (useful for testing).\\n54\\t    pub fn open_in_memory() -\u003e Result\u003cSelf, AxonError\u003e {\\n55\\t        let conn = Connection::open_in_memory().map_err(|e| AxonError::Storage(e.to_string()))?;\\n56\\t        let adapter = Self {\\n57\\t            conn: Mutex::new(conn),\\n58\\t            in_tx: false,\\n59\\t        };\\n60\\t        adapter.init_schema()?;\\n61\\t        Ok(adapter)\\n62\\t    }\\n63\\t\\n64\\t    /// Acquire the inner `Connection` lock, converting a poisoned-mutex error into\\n65\\t    /// an `AxonError::Storage`.\\n66\\t    fn conn(\u0026self) -\u003e Result\u003cMutexGuard\u003c'_, Connection\u003e, AxonError\u003e {\\n67\\t        self.conn\\n68\\t            .lock()\\n69\\t            .map_err(|e