t!(nobody.check(Operation::Admin).is_err());\\n449\\t    }\\n450\\t\\n451\\t    #[test]\\n452\\t    fn write_denied_error_is_descriptive() {\\n453\\t        let reader = CallerIdentity::new(\\\"charlie\\\", Role::Read);\\n454\\t        let err = reader\\n455\\t            .check(Operation::Write)\\n456\\t            .expect_err(\\\"read role should not be allowed to write\\\");\\n457\\t        let msg = err.to_string();\\n458\\t        assert!(msg.contains(\\\"permission denied\\\"), \\\"msg: {msg}\\\");\\n459\\t        assert!(msg.contains(\\\"read\\\"), \\\"msg: {msg}\\\");\\n460\\t        assert!(msg.contains(\\\"write\\\"), \\\"msg: {msg}\\\");\\n461\\t    }\\n462\\t\\n463\\t    // ── Field-level masking tests (US-046) ──────────────────────────────\\n464\\t\\n465\\t    #[test]\\n466\\t    fn admin_sees_all_fields() {\\n467\\t        let admin = CallerIdentity::new(\\\"admin\\\", Role::Admin);\\n468\\t        let mut data = serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"salary\\\": 100000});\\n469\\t        let policies = vec![MaskPolicy {\\n470\\t            field: \\\"salary\\\".into(),\\n471\\t            min_role: Role::Admin,\\n472\\t        }];\\n473\\t        admin.apply_masks(\u0026mut data, \u0026policies);\\n474\\t        assert!(data.get(\\\"salary\\\").is_some(), \\\"admin should see salary\\\");\\n475\\t    }\\n476\\t\\n477\\t    #[test]\\n478\\t    fn reader_cannot_see_admin_only_fields() {\\n479\\t        let reader = CallerIdentity::new(\\\"bob\\\", Role::Read);\\n480\\t        let mut data =\\n481\\t            serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"salary\\\": 100000, \\\"email\\\": \\\"alice@co.com\\\"});\\n482\\t        let policies = vec![MaskPolicy {\\n483\\t            field: \\\"salary\\\".into(),\\n484\\t            min_role: Role::Admin,\\n485\\t        }];\\n486\\t        reader.apply_masks(\u0026mut data, \u0026policies);\\n487\\t        assert!(data.get(\\\"salary\\\").is_none(), \\\"reader should not see salary\\\");\\n488\\t        assert!(data.get(\\\"name\\\").is_some(), \\\"name is not masked\\\");\\n489\\t        assert!(data.get(\\\"email\\\").is_some(), \\\"email is not masked\\\");\\n490\\t    }\\n491\\t\\n492\\t    #[test]\\n493\\t    fn writer_sees_write_level_fields() {\\n494\\t        let writer = CallerIdentity::new(\\\"charlie\\\", Role::Write);\\n495\\t        let mut data = serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"internal_notes\\\": \\\"sensitive\\\"});\\n496\\t        let policies = vec![MaskPolicy {\\n497\\t            field: \\\"internal_notes\\\".into(),\\n498\\t            min_role: Role::Write,\\n499\\t        }];\\n500\\t        writer.apply_masks(\u0026mut data, \u0026policies);\\n501\\t        assert!(\\n502\\t            data.get(\\\"internal_notes\\\").is_some(),\\n503\\t            \\\"writer should see write-level fields\\\"\\n504\\t        );\\n505\\t    }\\n506\\t\\n507\\t    #[test]\\n508\\t    fn reader_cannot_see_write_level_fields() {\\n509\\t        let reader = CallerIdentity::new(\\\"dave\\\", Role::Read);\\n510\\t        let mut data = serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"internal_notes\\\": \\\"sensitive\\\"});\\n511\\t        let policies = vec![MaskPolicy {\\n512\\t            field: \\\"internal_notes\\\".into(),\\n513\\t            min_role: Role::Write,\\n514\\t        }];\\n515\\t        reader.apply_masks(\u0026mut data, \u0026policies);\\n516\\t        assert!(\\n517\\t            data.get(\\\"internal_notes\\\").is_none(),\\n518\\t            \\\"reader should not see write-level fields\\\"\\n519\\t        );\\n520\\t    }\\n521\\t\\n522\\t    #[test]\\n523\\t    fn multiple_mask_policies() {\\n524\\t        let reader = CallerIdentity::new(\\\"eve\\\", Role::Read);\\n525\\t        let mut data = serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"salary\\\": 100000, \\\"ssn\\\": \\\"123-45-6789\\\"});\\n526\\t        let policies = vec![\\n527\\t            MaskPolicy {\\n528\\t                field: \\\"salary\\\".into(),\\n529\\t                min_role: Role::Admin,\\n530\\t            },\\n531\\t            MaskPolicy {\\n532\\t                field: \\\"ssn\\\".into(),\\n533\\t                min_role: Role::Write,\\n534\\t            },\\n535\\t        ];\\n536\\t        reader.apply_masks(\u0026mut data, \u0026policies);\\n537\\t        assert!(data.get(\\\"salary\\\").is_none());\\n538\\t        assert!(data.get(\\\"ssn\\\").is_none());\\n539\\t        assert!(data.get(\\\"name\\\").is_some());\\n540\\t    }\\n541\\t\\n542\\t    #[test]\\n543\\t    fn mask_on_non_object_is_noop() {\\n544\\t        let reader = CallerIdentity::new(\\\"f\\\", Role::Read);\\n545\\t        let mut data = serde_json::json!(\\\"just a string\\\");\\n546\\t        let policies = vec![MaskPolicy {\\n547\\t            field: \\\"anything\\\".into(),\\n548\\t            min_role: Role::Admin,\\n549\\t        }];\\n550\\t        reader.apply_masks(\u0026mut data, \u0026policies);\\n551\\t        assert_eq!(data, serde_json::json!(\\\"just a string\\\"));\\n552\\t    }\\n553\\t\\n554\\t    // ── ABAC write policy tests (US-047) ───────────────────────────────\\n555\\t\\n556\\t    #[test]\\n557\\t    fn write_policy_allows_matching_role() {\\n558\\t        let policy = WritePolicy {\\n559\\t            collection: \\\"tasks\\\".into(),\\n560\\t            min_write_role: Role::Write,\\n561\\t            immutable_fields: vec![],\\n562\\t        };\\n563\\t        let caller = CallerIdentity::new(\\\"alice\\\", Role::Write);\\n564\\t        assert!(policy.check_write(\u0026caller).is_ok());\\n565\\t    }\\n566\\t\\n567\\t    #[test]\\n568\\t    fn write_policy_denies_insufficient_role() {\\n569\\t        let policy = WritePolicy {\\n570\\t            collection: \\\"tasks\\\".into(),\\n571\\t            min_write_role: Role::Admin,\\n572\\t            immutable_fields: vec![],\\n573\\t        };\\n574\\t        let caller = CallerIdentity::new(\\\"bob\\\", Role::Write);\\n575\\t        assert!(policy.check_write(\u0026caller).is_err());\\n576\\t    }\\n577\\t\\n578\\t    #[test]\\n579\\t    fn immutable_fields_detected() {\\n580\\t        let policy = WritePolicy {\\n581\\t            collection: \\\"tasks\\\".into(),\\n582\\t            min_write_role: Role::Write,\\n583\\t            immutable_fields: vec![\\\"created_by\\\".into(), \\\"source\\\".into()],\\n584\\t        };\\n585\\t\\n586\\t        let old_data = serde_json::json!({\\\"title\\\": \\\"T\\\", \\\"created_by\\\": \\\"alice\\\", \\\"source\\\": \\\"api\\\"});\\n587\\t        let new_data = serde_json::json!({\\\"title\\\": \\\"T2\\\", \\\"created_by\\\": \\\"alice\\\", \\\"source\\\": \\\"api\\\"});\\n588\\t        let violations = policy.check_immutable_fields(\u0026old_data, \u0026new_data);\\n589\\t        assert!(violations.is_empty());\\n590\\t\\n591\\t        let changed = serde_json::json!({\\\"title\\\": \\\"T2\\\", \\\"created_by\\\": \\\"bob\\\", \\\"source\\\": \\\"api\\\"});\\n592\\t        let violations = policy.check_immutable_fields(\u0026old_data, \u0026changed);\\n593\\t        assert_eq!(violations, vec![\\\"created_by\\\"]);\\n594\\t    }\\n595\\t\\n596\\t    #[test]\\n597\\t    fn immutable_field_added_is_ok() {\\n598\\t        // Adding an immutable field to an entity that didn't have it is OK.\\n599\\t        let policy = WritePolicy {\\n600\\t            collection: \\\"tasks\\\".into(),\\n601\\t            min_write_role: Role::Write,\\n602\\t            immutable_fields: vec![\\\"locked\\\".into()],\\n603\\t        };\\n604\\t        let old_data = serde_json::json!({\\\"title\\\": \\\"T\\\"});\\n605\\t        let new_data = serde_json::json!({\\\"title\\\": \\\"T\\\", \\\"locked\\\": true});\\n606\\t        let violations = policy.check_immutable_fields(\u0026old_data, \u0026new_data);\\n607\\t        assert!(violations.is_empty());\\n608\\t    }\\n609\\t\\n610\\t    #[test]\\n611\\t    fn immutable_field_removed_is_violation() {\\n612\\t        let policy = WritePolicy {\\n613\\t            collection: \\\"tasks\\\".into(),\\n614\\t            min_write_role: Role::Write,\\n615\\t            immutable_fields: vec![\\\"source\\\".into()],\\n616\\t        };\\n617\\t        let old_data = serde_json::json!({\\\"title\\\": \\\"T\\\", \\\"source\\\": \\\"api\\\"});\\n618\\t        let new_data = serde_json::json!({\\\"title\\\": \\\"T2\\\"});\\n619\\t        let violations = policy.check_immutable_fields(\u0026old_data, \u0026new_data);\\n620\\t        assert_eq!(violations, vec![\\\"source\\\"]);\\n621\\t    }\\n622\\t\\n623\\t    // ── Database grant tests (US-038) ──────────────────────────────────\\n624\\t\\n625\\t    #[test]\\n626\\t    fn grant_registry_empty_denies_all() {\\n627\\t        let registry = GrantRegistry::new();\\n628\\t        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::None);\\n629\\t        assert!(registry.check(\\\"alice\\\", \\\"prod\\\", Operation::Read).is_err());\\n630\\t    }\\n631\\t\\n632\\t    #[test]\\n633\\t    fn exact_grant_allows_access() {\\n634\\t        let mut registry = GrantRegistry::new();\\n635\\t        registry.add(DatabaseGrant {\\n636\\t            actor: \\\"alice\\\".into(),\\n637\\t            database: \\\"prod\\\".into(),\\n638\\t            role: Role::Write,\\n639\\t        });\\n640\\t        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::Write);\\n641\\t        assert!(registry.check(\\\"alice\\\", \\\"prod\\\", Operation::Write).is_ok());\\n642\\t        assert!(registry.check(\\\"alice\\\", \\\"prod\\\", Operation::Admin).is_err());\\n643\\t    }\\n644\\t\\n645\\t    #[test]\\n646\\t    fn wildcard_actor_grant() {\\n647\\t        let mut registry = GrantRegistry::new();\\n648\\t        registry.add(DatabaseGrant {\\n649\\t            actor: \\\"*\\\".into(),\\n650\\t            database: \\\"public\\\".into(),\\n651\\t            role: Role::Read,\\n652\\t        });\\n653\\t        assert_eq!(registry.effective_role(\\\"anyone\\\", \\\"public\\\"), Role::Read);\\n654\\t        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"public\\\"), Role::Read);\\n655\\t    }\\n656\\t\\n657\\t    #[test]\\n658\\t    fn wildcard_database_grant() {\\n659\\t        let mut registry = GrantRegistry::new();\\n660\\t        registry.add(DatabaseGrant {\\n661\\t            actor: \\\"admin-bot\\\".into(),\\n662\\t            database: \\\"*\\\".into(),\\n663\\t            role: Role::Admin,\\n664\\t        });\\n665\\t        assert_eq!(\\n666\\t            registry.effective_role(\\\"admin-bot\\\", \\\"any-database\\\"),\\n667\\t            Role::Admin\\n668\\t        );\\n669\\t    }\\n670\\t\\n671\\t    #[test]\\n672\\t    fn highest_privilege_wins() {\\n673\\t        let mut registry = GrantRegistry::new();\\n674\\t        registry.add(DatabaseGrant {\\n675\\t            actor: \\\"alice\\\".into(),\\n676\\t            database: \\\"prod\\\".into(),\\n677\\t            role: Role::Read,\\n678\\t        });\\n679\\t        registry.add(DatabaseGrant {\\n680\\t            actor: \\\"alice\\\".into(),\\n681\\t            database: \\\"prod\\\".into(),\\n682\\t            role: Role::Admin,\\n683\\t        });\\n684\\t        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::Admin);\\n685\\t    }\\n686\\t\\n687\\t    #[test]\\n688\\t    fn no_cross_database_access_without_grant() {\\n689\\t        let mut registry = GrantRegistry::new();\\n690\\t        registry.add(DatabaseGrant {\\n691\\t            actor: \\\"alice\\\".into(),\\n692\\t            database: \\\"dev\\\".into(),\\n693\\t            role: Role::Admin,\\n694\\t        });\\n695\\t        // alice has no grant on prod\\n696\\t        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::None);\\n697\\t    }\\n698\\t\\n699\\t    #[test]\\n700\\t    fn revoke_removes_grants() {\\n701\\t        let mut registry = GrantRegistry::new();\\n702\\t        registry.add(DatabaseGrant {\\n703\\t            actor: \\\"alice\\\".into(),\\n704\\t            database: \\\"prod\\\".into(),\\n705\\t            role: Role::Write,\\n706\\t        });\\n707\\t        registry.revoke(\\\"alice\\\", \\\"prod\\\");\\n708\\t        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::None);\\n709\\t    }\\n710\\t}\\n711\\t\\n712\\t// ── ADR-018: Tenant/User/Credential types ───────────────────────────────────\\n713\\t\\n714\\tuse uuid::Uuid;\\n715\\t\\n716\\t/// Stable identifier for a tenant.\\n717\\t#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]\\n718\\t#[serde(transparent)]\\n719\\tpub struct TenantId(pub String);\\n720\\t\\n721\\timpl TenantId {\\n722\\t    /// Generate a fresh tenant id (UUIDv7 string).\\n723\\t    pub fn generate() -\u003e Self {\\n724\\t        Self(Uuid::now_v7().to_string())\\n725\\t    }\\n726\\t\\n727\\t    /// Wrap an existing id string.\\n728\\t    pub fn new(id: impl Into\u003cString\u003e) -\u003e Self {\\n729\\t        Self(id.into())\\n730\\t    }\\n731\\t\\n732\\t    pub fn as_str(\u0026self) -\u003e \u0026str {\\n733\\t        \u0026self.0\\n734\\t    }\\n735\\t}\\n736\\t\\n737\\timpl std::fmt::Display for TenantId {\\n738\\t    fn fmt(\u0026self, f: \u0026mut std::fmt::Formatter\u003c'_\u003e) -\u003e std::fmt::Result {\\n739\\t        write!(f, \\\"{}\\\", self.0)\\n740\\t    }\\n741\\t}\\n742\\t\\n743\\t/// Stable identifier for a user.\\n744\\t#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]\\n745\\t#[serde(transparent)]\\n746\\tpub struct UserId(pub String);\\n747\\t\\n748\\timpl UserId {\\n749\\t    /// Generate a fresh user id (UUIDv7 string).\\n750\\t    pub fn generate() -\u003e Self {\\n751\\t        Self(Uuid::now_v7().to_string())\\n752\\t    }\\n753\\t\\n754\\t    /// Wrap an existing id string.\\n755\\t    pub fn new(id: impl Into\u003cString\u003e) -\u003e Self {\\n756\\t        Self(id.into())\\n757\\t    }\\n758\\t\\n759\\t    pub fn as_str(\u0026self) -\u003e \u0026str {\\n760\\t        \u0026self.0\\n761\\t    }\\n762\\t}\\n763\\t\\n764\\timpl std::fmt::Display for UserId {\\n765\\t    fn fmt(\u0026self, f: \u0026mut std::fmt::Formatter\u003c'_\u003e) -\u003e std::fmt::Result {\\n766\\t        write!(f, \\\"{}\\\", self.0)\\n767\\t    }\\n768\\t}\\n769\\t\\n770\\t/// A tenant (global account boundary).\\n771\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n772\\tpub struct Tenant {\\n773\\t    pub id: TenantId,\\n774\\t    pub name: String,\\n775\\t    pub created_at_ms: u64,\\n776\\t}\\n777\\t\\n778\\t/// A user (global identity).\\n779\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n780\\tpub struct User {\\n781\\t    pub id: UserId,\\n782\\t    pub display_name: String,\\n783\\t    #[serde(default, skip_serializing_if = \\\"Option::is_none\\\")]\\n784\\t    pub email: Option\u003cString\u003e,\\n785\\t    pub created_at_ms: u64,\\n786\\t    #[serde(default, skip_serializing_if = \\\"Option::is_none\\\")]\\n787\\t    pub suspended_at_ms: Option\u003cu64\u003e,\\n788\\t}\\n789\\t\\n790\\t/// External identity that federates to a user.\\n791\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n792\\tpub struct UserIdentity {\\n793\\t    pub provider: String,\\n794\\t    pub external_id: String,\\n795\\t    pub user_id: UserId,\\n796\\t}\\n797\\t\\n798\\t/// A user's membership in a tenant.\\n799\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n800\\tpub struct TenantMember {\\n801\\t    pub tenant_id: TenantId,\\n802\\t    pub user_id: UserId,\\n803\\t    pub role: TenantRole,\\n804\\t}\\n805\\t\\n806\\t/// Role a user has within a tenant.\\n807\\t#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord, Hash, Serialize, Deserialize)]\\n808\\tpub enum TenantRole {\\n809\\t    Admin,\\n810\\t    Write,\\n811\\t    Read,\\n812\\t}\\n813\\t\\n814\\timpl TenantRole {\\n815\\t    /// Returns the operations this role can delegate (ceiling).\\n816\\t    ///\\n817\\t    /// - `Admin` → `{Read, Write, Admin}`\\n818\\t    /// - `Write` → `{Read, Write}`\\n819\\t    /// - `Read` → `{Read}`\\n820\\t    pub fn delegation_ops(\u0026self) -\u003e Vec\u003cOp\u003e {\\n821\\t        match self {\\n822\\t            TenantRole::Admin =\u003e vec![Op::Read, Op::Write, Op::Admin],\\n823\\t            TenantRole::Write =\u003e vec![Op::Read, Op::Write],\\n824\\t            TenantRole::Read =\u003e vec![Op::Read],\\n825\\t        }\\n826\\t    }\\n827\\t}\\n828\\t\\n829\\t/// An operation that can be granted.\\n830\\t#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]\\n831\\tpub enum Op {\\n832\\t    Read,\\n833\\t    Write,\\n834\\t    Admin,\\n835\\t}\\n836\\t\\n837\\t/// A database with a set of granted operations.\\n838\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n839\\tpub struct GrantedDatabase {\\n840\\t    pub name: String,\\n841\\t    pub ops: Vec\u003cOp\u003e,\\n842\\t}\\n843\\t\\n844\\t/// A collection of database grants.\\n845\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n846\\tpub struct Grants {\\n847\\t    pub databases: Vec\u003cGrantedDatabase\u003e,\\n848\\t}\\n849\\t\\n850\\timpl Grants {\\n851\\t    /// Validate the grants structure according to the v5 schema.\\n852\\t    ///\\n853\\t    /// - At most 1024 databases\\n854\\t    /// - Each database must have at least one op\\n855\\t    /// - Each op must be unique (no duplicates)\\n856\\t    pub fn validate(\u0026self) -\u003e Result\u003c(), AuthError\u003e {\\n857\\t        if self.databases.len() \u003e 1024 {\\n858\\t            return Err(AuthError::GrantsMalformed);\\n859\\t        }\\n860\\t        for db in \u0026self.databases {\\n861\\t            db.validate()?;\\n862\\t        }\\n863\\t        Ok(())\\n864\\t    }\\n865\\t}\\n866\\t\\n867\\timpl GrantedDatabase {\\n868\\t    /// Validate a single granted database.\\n869\\t    ///\\n870\\t    /// - name must be non-empty\\n871\\t    /// - ops must not be empty\\n872\\t    /// - ops must be unique\\n873\\t    pub fn validate(\u0026self) -\u003e Result\u003c(), AuthError\u003e {\\n874\\t        if self.name.is_empty() {\\n875\\t            return Err(AuthError::GrantsMalformed);\\n876\\t        }\\n877\\t        if self.ops.is_empty() {\\n878\\t            return Err(AuthError::GrantsMalformed);\\n879\\t        }\\n880\\t        // Check for duplicate ops\\n881\\t        let unique_ops: std::collections::HashSet\u003c_\u003e = self.ops.iter().collect();\\n882\\t        if unique_ops.len() != self.ops.len() {\\n883\\t            return Err(AuthError::GrantsMalformed);\\n884\\t        }\\n885\\t        Ok(())\\n886\\t    }\\n887\\t}\\n888\\t\\n889\\t/// JWT claims for tenant-scoped credentials (ADR-018 §4).\\n890\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n891\\tpub struct JwtClaims {\\n892\\t    pub iss: String,\\n893\\t    pub sub: String,\\n894\\t    pub aud: String,\\n895\\t    pub jti: String,\\n896\\t    pub iat: u64,\\n897\\t    pub nbf: u64,\\n898\\t    pub exp: u64,\\n899\\t    pub grants: Grants,\"}]},\"parent_tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"2d11be8a-1054-47c1-b2e6-60ab6bd947cf\",\"timestamp\":\"2026-04-15T01:31:06.078Z\"}\n{\"type\":\"user\",\"message\":{\"role\":\"user\",\"content\":[{\"tool_use_id\":\"toolu_017GHCJLm7sSs2NeYW5LxZ8x\",\"type\":\"tool_result\",\"content\":\"900\\t}\\n901\\t\\n902\\timpl JwtClaims {\\n903\\t    /// Validate the JWT claims structure.\\n904\\t    ///\\n905\\t    /// Returns `AuthError::CredentialMalformed` if:\\n906\\t    /// - `aud` is not a single string (e.g., it was a JSON array)\\n907\\t    /// - Grants don't match the expected schema\\n908\\t    ///\\n909\\t    /// This is typically used after deserialization to catch schema violations\\n910\\t    /// that serde doesn't catch by itself (e.g., aud as an array).\\n911\\t    pub fn validate(\u0026self) -\u003e Result\u003c(), AuthError\u003e {\\n912\\t        // Check grants structure\\n913\\t        self.grants.validate()?;\\n914\\t        Ok(())\\n915\\t    }\\n916\\t}\\n917\\t\\n918\\t/// Authentication error variants (ADR-018 §4 failure-mode table).\\n919\\t///\\n920\\t/// This enum has exactly 14 variants matching the failure modes in\\n921\\t/// ADR-018 §4 \\\"JWT failure mode → HTTP status + error code\\\".\\n922\\t#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]\\n923\\tpub enum AuthError {\\n924\\t    /// No `Authorization` header (non-`--no-auth` mode).\\n925\\t    Unauthenticated,\\n926\\t\\n927\\t    /// Header present but not `Bearer \u003ctoken\u003e`, or JWT structurally invalid,\\n928\\t    /// or `aud` claim is a JSON array instead of a string.\\n929\\t    CredentialMalformed,\\n930\\t\\n931\\t    /// Signature invalid (wrong key or tampered payload).\\n932\\t    CredentialInvalid,\\n933\\t\\n934\\t    /// `exp` claim is in the past.\\n935\\t    CredentialExpired,\\n936\\t\\n937\\t    /// `nbf` claim is in the future.\\n938\\t    CredentialNotYetValid,\\n939\\t\\n940\\t    /// `jti` claim is present in the revocation list.\\n941\\t    CredentialRevoked,\\n942\\t\\n943\\t    /// `iss` claim does not match this deployment's issuer.\\n944\\t    CredentialForeignIssuer,\\n945\\t\\n946\\t    /// `aud` claim does not match the tenant in the URL path.\\n947\\t    CredentialWrongTenant,\\n948\\t\\n949\\t    /// `sub` claim resolves to a suspended or deleted user.\\n950\\t    UserSuspended,\\n951\\t\\n952\\t    /// `sub` claim is not a member of the tenant in the URL path.\\n953\\t    NotATenantMember,\\n954\\t\\n955\\t    /// URL `{database}` segment not found in `grants.databases[]`.\\n956\\t    DatabaseNotGranted,\\n957\\t\\n958\\t    /// Required operation not in the matching grant's `ops[]`.\\n959\\t    OpNotGranted,\\n960\\t\\n961\\t    /// Grant scope exceeds issuer's role at issuance time.\\n962\\t    GrantsExceedIssuerRole,\\n963\\t\\n964\\t    /// Malformed grants payload (schema validation failure).\\n965\\t    GrantsMalformed,\\n966\\t}\\n967\\t\\n968\\timpl std::fmt::Display for AuthError {\\n969\\t    fn fmt(\u0026self, f: \u0026mut std::fmt::Formatter\u003c'_\u003e) -\u003e std::fmt::Result {\\n970\\t        match self {\\n971\\t            AuthError::Unauthenticated =\u003e write!(f, \\\"unauthenticated\\\"),\\n972\\t            AuthError::CredentialMalformed =\u003e write!(f, \\\"credential malformed\\\"),\\n973\\t            AuthError::CredentialInvalid =\u003e write!(f, \\\"credential invalid\\\"),\\n974\\t            AuthError::CredentialExpired =\u003e write!(f, \\\"credential expired\\\"),\\n975\\t            AuthError::CredentialNotYetValid =\u003e write!(f, \\\"credential not yet valid\\\"),\\n976\\t            AuthError::CredentialRevoked =\u003e write!(f, \\\"credential revoked\\\"),\\n977\\t            AuthError::CredentialForeignIssuer =\u003e write!(f, \\\"credential foreign issuer\\\"),\\n978\\t            AuthError::CredentialWrongTenant =\u003e write!(f, \\\"credential wrong tenant\\\"),\\n979\\t            AuthError::UserSuspended =\u003e write!(f, \\\"user suspended\\\"),\\n980\\t            AuthError::NotATenantMember =\u003e write!(f, \\\"not a tenant member\\\"),\\n981\\t            AuthError::DatabaseNotGranted =\u003e write!(f, \\\"database not granted\\\"),\\n982\\t            AuthError::OpNotGranted =\u003e write!(f, \\\"op not granted\\\"),\\n983\\t            AuthError::GrantsExceedIssuerRole =\u003e write!(f, \\\"grants exceed issuer role\\\"),\\n984\\t            AuthError::GrantsMalformed =\u003e write!(f, \\\"grants malformed\\\"),\\n985\\t        }\\n986\\t    }\\n987\\t}\\n988\\t\\n989\\timpl std::error::Error for AuthError {}\\n990\\t\\n991\\timpl From\u003cserde_json::Error\u003e for AuthError {\\n992\\t    fn from(_: serde_json::Error) -\u003e Self {\\n993\\t        AuthError::CredentialMalformed\\n994\\t    }\\n995\\t}\\n996\\t\\n997\\t/// Parse a JSON string into [`JwtClaims`], mapping any deserialization error\\n998\\t/// to [`AuthError::CredentialMalformed`].\\n999\\tpub fn parse_claims(s: \u0026str) -\u003e Result\u003cJwtClaims, AuthError\u003e {\\n1000\\t    serde_json::from_str(s).map_err(AuthError::from)\\n1001\\t}\\n1002\\t\\n1003\\t/// Compile-time exhaustive check that `AuthError` has exactly 14 variants\\n1004\\t/// (ADR-018 §4). Adding or removing a variant without updating this match\\n1005\\t/// will cause a compile error.\\n1006\\tconst _: () = {\\n1007\\t    const fn _exhaustive_variant_check(e: \u0026AuthError) -\u003e usize {\\n1008\\t        match e {\\n1009\\t            AuthError::Unauthenticated =\u003e 0,\\n1010\\t            AuthError::CredentialMalformed =\u003e 1,\\n1011\\t            AuthError::CredentialInvalid =\u003e 2,\\n1012\\t            AuthError::CredentialExpired =\u003e 3,\\n1013\\t            AuthError::CredentialNotYetValid =\u003e 4,\\n1014\\t            AuthError::CredentialRevoked =\u003e 5,\\n1015\\t            AuthError::CredentialForeignIssuer =\u003e 6,\\n1016\\t            AuthError::CredentialWrongTenant =\u003e 7,\\n1017\\t            AuthError::UserSuspended =\u003e 8,\\n1018\\t            AuthError::NotATenantMember =\u003e 9,\\n1019\\t            AuthError::DatabaseNotGranted =\u003e 10,\\n1020\\t            AuthError::OpNotGranted =\u003e 11,\\n1021\\t            AuthError::GrantsExceedIssuerRole =\u003e 12,\\n1022\\t            AuthError::GrantsMalformed =\u003e 13,\\n1023\\t        }\\n1024\\t    }\\n1025\\t    // Suppress unused-function lint in const context.\\n1026\\t    let _ = _exhaustive_variant_check;\\n1027\\t};\\n1028\\t\\n1029\\t#[cfg(test)]\\n1030\\tmod auth_core_tests {\\n1031\\t    use super::*;\\n1032\\t\\n1033\\t    // ── Type round-trip tests (Serde) ──────────────────────────────────\\n1034\\t\\n1035\\t    #[test]\\n1036\\t    fn tenant_id_roundtrip() {\\n1037\\t        let id = TenantId::new(\\\"t-123\\\");\\n1038\\t        let json = serde_json::to_string(\u0026id).unwrap();\\n1039\\t        assert_eq!(json, \\\"\\\\\\\"t-123\\\\\\\"\\\");\\n1040\\t        let parsed: TenantId = serde_json::from_str(\u0026json).unwrap();\\n1041\\t        assert_eq!(parsed, id);\\n1042\\t    }\\n1043\\t\\n1044\\t    #[test]\\n1045\\t    fn user_id_roundtrip() {\\n1046\\t        let id = UserId::new(\\\"u-456\\\");\\n1047\\t        let json = serde_json::to_string(\u0026id).unwrap();\\n1048\\t        assert_eq!(json, \\\"\\\\\\\"u-456\\\\\\\"\\\");\\n1049\\t        let parsed: UserId = serde_json::from_str(\u0026json).unwrap();\\n1050\\t        assert_eq!(parsed, id);\\n1051\\t    }\\n1052\\t\\n1053\\t    #[test]\\n1054\\t    fn tenant_roundtrip() {\\n1055\\t        let tenant = Tenant {\\n1056\\t            id: TenantId::new(\\\"t-123\\\"),\\n1057\\t            name: \\\"acme\\\".into(),\\n1058\\t            created_at_ms: 1000,\\n1059\\t        };\\n1060\\t        let json = serde_json::to_string(\u0026tenant).unwrap();\\n1061\\t        let parsed: Tenant = serde_json::from_str(\u0026json).unwrap();\\n1062\\t        assert_eq!(parsed, tenant);\\n1063\\t    }\\n1064\\t\\n1065\\t    #[test]\\n1066\\t    fn user_roundtrip() {\\n1067\\t        let user = User {\\n1068\\t            id: UserId::new(\\\"u-123\\\"),\\n1069\\t            display_name: \\\"Alice\\\".into(),\\n1070\\t            email: Some(\\\"alice@example.com\\\".into()),\\n1071\\t            created_at_ms: 1000,\\n1072\\t            suspended_at_ms: None,\\n1073\\t        };\\n1074\\t        let json = serde_json::to_string(\u0026user).unwrap();\\n1075\\t        let parsed: User = serde_json::from_str(\u0026json).unwrap();\\n1076\\t        assert_eq!(parsed, user);\\n1077\\t    }\\n1078\\t\\n1079\\t    #[test]\\n1080\\t    fn user_without_email_roundtrip() {\\n1081\\t        let user = User {\\n1082\\t            id: UserId::new(\\\"u-123\\\"),\\n1083\\t            display_name: \\\"Bob\\\".into(),\\n1084\\t            email: None,\\n1085\\t            created_at_ms: 1000,\\n1086\\