// TestMain clears all GIT_* environment variables before running tests so
// that tests invoking git commands operate on their own temp-dir repositories
// rather than any repository inherited from a hook invocation (e.g. GIT_DIR
// set by lefthook during pre-commit). Prefix scrub is important — lefthook
// sets GIT_AUTHOR_NAME, GIT_COMMITTER_EMAIL, GIT_CONFIG_PARAMETERS etc. that
// also leak into test subprocesses and corrupt the shared repo config.
func TestMain(m *testing.M) {
	for _, kv := range os.Environ() {
		if strings.HasPrefix(kv, "GIT_") {
			if idx := strings.IndexByte(kv, '='); idx >= 0 {
				_ = os.Unsetenv(kv[:idx])
			}
		}
	}
	os.Exit(m.Run())
}

var (
	testLibraryPath string
	testLibraryOnce sync.Once
)

// GetTestLibraryPath returns the absolute path to a bare git repository
// that mimics a real upstream library (like GitHub). This is the ONLY way
// tests should get the test library path.
func GetTestLibraryPath() string {
	testLibraryOnce.Do(func() {
		// Find the test fixtures directory
		_, filename, _, _ := runtime.Caller(0)
		cmdDir := filepath.Dir(filename)
		fixtureDir := filepath.Join(cmdDir, "..", "test", "fixtures", "ddx-library")
		fixtureDir, _ = filepath.Abs(fixtureDir)

		// Determine base temp directory: TMP -> TMPDIR -> /tmp
		tempBase := "/tmp"
		if tmp := os.Getenv("TMP"); tmp != "" {
			tempBase = tmp
		} else if tmpdir := os.Getenv("TMPDIR"); tmpdir != "" {
			tempBase = tmpdir
		}

		workingRepo := filepath.Join(tempBase, ".test-library")
		bareRepo := filepath.Join(tempBase, ".test-library.git")
		testLibraryPath = bareRepo

		// Check if we need to recreate (fixtures changed or doesn't exist)
		needsRecreate := false
		if stat, err := os.Stat(bareRepo); err != nil || !stat.IsDir() {
			needsRecreate = true
		} else if os.Getenv("CI") == "" {
			// In local dev, check if any fixture is newer than the repo
			repoModTime := stat.ModTime()
			filepath.Walk(fixtureDir, func(path string, info os.FileInfo, err error) error {
				if err == nil && !info.IsDir() && info.ModTime().After(repoModTime) {
					needsRecreate = true
				}
				return nil
			})
		}

		if needsRecreate {
			// Clean up old repos
			os.RemoveAll(workingRepo)
			os.RemoveAll(bareRepo)

			// Create working repo and copy fixtures
			if err := os.MkdirAll(workingRepo, 0755); err != nil {
				panic(fmt.Sprintf("Failed to create working repo: %v", err))
			}

			if err := syncDirectory(fixtureDir, workingRepo); err != nil {
				panic(fmt.Sprintf("Failed to copy fixtures: %v", err))
			}

			// Initialize git repo
			cmds := []struct {
				args []string
				dir  string
			}{
				{[]string{"git", "init", "-b", "master"}, workingRepo},
				{[]string{"git", "config", "user.email", "test@example.com"}, workingRepo},
				{[]string{"git", "config", "user.name", "Test User"}, workingRepo},
				{[]string{"git", "add", "."}, workingRepo},
				{[]string{"git", "commit", "--allow-empty", "-m", "Test fixture"}, workingRepo},
				{[]string{"git", "init", "--bare", bareRepo}, ""},
				{[]string{"git", "remote", "add", "origin", bareRepo}, workingRepo},
				{[]string{"git", "push", "origin", "master"}, workingRepo},
			}

			for _, c := range cmds {
				cmd := exec.Command(c.args[0], c.args[1:]...)
				if c.dir != "" {
					cmd.Dir = c.dir
				}
				if output, err := cmd.CombinedOutput(); err != nil {
					panic(fmt.Sprintf("Failed to run %v: %v\nOutput: %s", c.args, err, output))
				}
			}
		}
	})
	return testLibraryPath
}

// syncDirectory copies files from src to dst, preserving directory structure
func syncDirectory(src, dst string) error {
	return filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		// Skip .git directories from source
		if info.IsDir() && info.Name() == ".git" {
			return filepath.SkipDir
		}

		// Calculate relative path
		relPath, err := filepath.Rel(src, path)
		if err != nil {
			return err
		}

		dstPath := filepath.Join(dst, relPath)

		if info.IsDir() {
			return os.MkdirAll(dstPath, info.Mode())
		}

		// Copy file
		srcFile, err := os.Open(path)
		if err != nil {
			return err
		}
		defer func() { _ = srcFile.Close() }()

		dstFile, err := os.Create(dstPath)
		if err != nil {
			return err
		}
		defer func() { _ = dstFile.Close() }()

		if _, err := dstFile.ReadFrom(srcFile); err != nil {
			return err

	}

	f := NewCommandFactory(root)
	cmd := f.newServerStateCommand()
	var out bytes.Buffer
	cmd.SetOut(&out)
	cmd.SetErr(&out)
	cmd.SetArgs([]string{"worktree-prune", "--project", root, "--dry-run"})
	if err := cmd.Execute(); err != nil {
		t.Fatalf("dry-run failed: %v", err)
	}
	dryRun := out.String()
	if !strings.Contains(dryRun, abandoned) || !strings.Contains(dryRun, orphan) {
		t.Fatalf("dry-run did not list abandoned and orphan worktrees: %s", dryRun)
	}
	if strings.Contains(dryRun, active) {
		t.Fatalf("dry-run must not target active worktree: %s", dryRun)
	}

	cmd = f.newServerStateCommand()
	out.Reset()
	cmd.SetOut(&out)
	cmd.SetErr(&out)
	cmd.SetArgs([]string{"worktree-prune", "--project", root, "--yes"})
	if err := cmd.Execute(); err != nil {
		t.Fatalf("prune failed: %v; output=%s", err, out.String())
	}
	if _, err := os.Stat(active); err != nil {
		t.Fatalf("active worktree should remain: %v", err)
	}
	if _, err := os.Stat(abandoned); !os.IsNotExist(err) {
		t.Fatalf("abandoned worktree should be removed, stat err=%v", err)
	}
	if _, err := os.Stat(orphan); !os.IsNotExist(err) {
		t.Fatalf("orphan worktree should be removed, stat err=%v", err)
	}
}

func initWorktreePruneRepo(t *testing.T) string {
	t.Helper()
	root := t.TempDir()
	runGit(t, root, "init")
	runGit(t, root, "config", "user.email", "test@example.com")
	runGit(t, root, "config", "user.name", "Test User")
	if err := os.MkdirAll(filepath.Join(root, ".ddx"), 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(filepath.Join(root, "README.md"), []byte("fixture\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	runGit(t, root, "add", "README.md")
	runGit(t, root, "commit", "-m", "init")
	return root
}

func addPruneWorktree(t *testing.T, root, name string) string {
	t.Helper()
	path := filepath.Join(root, ".claude", "worktrees", "agent-"+name)
	runGit(t, root, "worktree", "add", "--detach", path, "HEAD")
	return path
}

func runGit(t *testing.T, dir string, args ...string) string {
	t.Helper()
	cmd := exec.Command("git", append([]string{"-C", dir}, args...)...)
	out, err := cmd.CombinedOutput()
	if err != nil {
		t.Fatalf("git %v failed: %s: %v", args, out, err)
	}
	return strings.TrimSpace(string(out))
}

// TestServerStatePruneDryRun verifies --dry-run prints the summary without
// writing any files.
func TestServerStatePruneDryRun(t *testing.T) {
	tmp := t.TempDir()
	statePath := filepath.Join(tmp, "server-state.json")

	now := time.Now().UTC().Format(time.RFC3339)
	state := map[string]any{
		"schema_version": "1",
		"node": map[string]any{
			"name": "test-node", "id": "node-test",
			"started_at": now, "last_seen": now,
		},
		"projects": []map[string]any{
			{"id": "p-real", "path": "/home/user/real", "registered_at": now, "last_seen": now},
			{"id": "p-fake", "path": "/tmp/TestFoo123/001", "registered_at": now, "last_seen": now},
		},
	}
	data, err := json.MarshalIndent(state, "", "  ")
	if err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(statePath, data, 0o600); err != nil {
		t.Fatal(err)
	}

	// Snapshot the mtime to verify the file was not rewritten.
	before, err := os.Stat(statePath)
	if err != nil {
		t.Fatal(err)
	}

	f := NewCommandFactory(tmp)
	root := f.newServerStateCommand()
	var out bytes.Buffer
	root.SetOut(&out)
	root.SetErr(&out)
	root.SetArgs([]string{"prune", "--dry-run", "--state", statePath})
	if err := root.Execute(); err != nil {
		t.Fatalf("dry-run prune returned error: %v", err)
	}

	got := out.String()
	if !strings.Contains(got, "DRY-RUN: Pruned 1 of 2 entries (1 kept)") {
		t.Errorf("unexpected summary: %q", got)
	}
	if strings.Contains(got, "Backup written to") {
		t.Errorf("dry-run must not write a backup; got %q", got)
	}

	// File should be byte-identical (no backup, no rewrite).
	after, err := os.Stat(statePath)
	if err != nil {
		t.Fatal(err)
	}
	if !after.ModTime().Equal(before.ModTime()) {
		t.Errorf("state file was modified during dry-run")
	}
	entries, err := os.ReadDir(tmp)
	if err != nil {
		t.Fatal(err)
	}
	for _, e := range entries {
		if strings.HasPrefix(e.Name(), "server-state.json.bak-") {
			t.Errorf("dry-run must not leave a backup; found %s", e.Name())
		}
	}
}

