func TestClassifyTable(t *testing.T) {
	now := time.Date(2026, 4, 23, 12, 0, 0, 0, time.UTC)
	old := now.Add(-25 * time.Hour)
	recent := now.Add(-time.Hour)
	tests := []struct {
		name string
		in   ClassificationInput
		want string
	}{
		{"active live worker", ClassificationInput{Registered: true, FSExists: true, Running: true, LastActivityAt: old, Now: now}, StateActive},
		{"active recent without worker", ClassificationInput{Registered: true, FSExists: true, LastActivityAt: recent, Now: now}, StateActive},
		{"active wins over completed evidence", ClassificationInput{Registered: true, FSExists: true, Running: true, HasVerdict: true, HeadRev: "b", ResultRev: "b", LastActivityAt: old, Now: now}, StateActive},
		{"completed matching head", ClassificationInput{Registered: true, FSExists: true, HasVerdict: true, HeadRev: "b", ResultRev: "b", LastActivityAt: old, Now: now}, StateCompleted},
		{"completed ignores age", ClassificationInput{Registered: true, FSExists: true, HasVerdict: true, HeadRev: "c", ResultRev: "c", LastActivityAt: now.Add(-90 * 24 * time.Hour), Now: now}, StateCompleted},
		{"completed needs verdict", ClassificationInput{Registered: true, FSExists: true, HeadRev: "c", ResultRev: "c", LastActivityAt: old, Now: now}, StateAbandoned},
		{"abandoned old no verdict", ClassificationInput{Registered: true, FSExists: true, LastActivityAt: old, Now: now}, StateAbandoned},
		{"abandoned mismatched result", ClassificationInput{Registered: true, FSExists: true, HasVerdict: true, HeadRev: "a", ResultRev: "b", LastActivityAt: old, Now: now}, StateAbandoned},
		{"abandoned custom threshold", ClassificationInput{Registered: true, FSExists: true, LastActivityAt: now.Add(-2 * time.Hour), Now: now, AbandonedAfter: time.Hour}, StateAbandoned},
		{"orphan disk only", ClassificationInput{Registered: false, FSExists: true, Running: true, LastActivityAt: recent, Now: now}, StateOrphan},
		{"orphan git only", ClassificationInput{Registered: true, FSExists: false, LastActivityAt: recent, Now: now}, StateOrphan},
		{"orphan wins over verdict", ClassificationInput{Registered: false, FSExists: true, HasVerdict: true, HeadRev: "a", ResultRev: "a", LastActivityAt: recent, Now: now}, StateOrphan},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if got := Classify(tt.in); got != tt.want {
				t.Fatalf("Classify() = %q, want %q", got, tt.want)
			}
		})
	}
}

func TestListClassifiesActiveCompletedAbandonedAndOrphan(t *testing.T) {
	ctx := context.Background()
	now := time.Date(2026, 4, 23, 12, 0, 0, 0, time.UTC)
	root := initRepo(t)
	base := git(t, root, "rev-parse", "HEAD")

	active := addWorktree(t, root, "active")
	completed := addWorktree(t, root, "completed")
	abandoned := addWorktree(t, root, "abandoned")
	orphan := filepath.Join(root, ".claude", "worktrees", "agent-orphan")
	if err := os.MkdirAll(orphan, 0o755); err != nil {
		t.Fatal(err)
	}

	writeBundle(t, root, "attempt-active", "ddx-active", base, "", active, now.Add(-30*time.Minute), time.Time{})
	completedHead := commitInWorktree(t, completed, "done.txt")
	writeBundle(t, root, "attempt-completed", "ddx-completed", base, completedHead, completed, now.Add(-2*time.Hour), now.Add(-90*time.Minute))
	writeBundle(t, root, "attempt-abandoned", "ddx-abandoned", base, "", abandoned, now.Add(-48*time.Hour), time.Time{})
	old := now.Add(-48 * time.Hour)
	if err := os.Chtimes(abandoned, old, old); err != nil {
		t.Fatal(err)
	}

	entries, err := List(ctx, root, InventoryOptions{
		Now:            now,
		AbandonedAfter: 24 * time.Hour,
		ActiveAttempts: []ActiveAttempt{{AttemptID: "attempt-active", BeadID: "ddx-active"}},
	})
	if err != nil {
		t.Fatal(err)
	}
	states := map[string]string{}
	for _, e := range entries {
		states[e.ExecutionID] = e.State
		if e.Path == orphan {
			states["orphan-path"] = e.State
		}
	}
	assertState(t, states, "attempt-active", StateActive)
	assertState(t, states, "attempt-completed", StateCompleted)
	assertState(t, states, "attempt-abandoned", StateAbandoned)
	assertState(t, states, "orphan-path", StateOrphan)

	counters := Count(entries)
	if counters.Total < 4 || counters.Active != 1 || counters.Completed != 1 || counters.Abandoned != 1 || counters.Orphan != 1 {
		t.Fatalf("unexpected counters: %+v", counters)
	}
}

func TestRemoveUsesGitForRegisteredAndFilesystemForOrphan(t *testing.T) {
	ctx := context.Background()
	root := initRepo(t)
	registered := addWorktree(t, root, "stale")
	old := time.Now().Add(-48 * time.Hour)
	if err := os.Chtimes(registered, old, old); err != nil {
		t.Fatal(err)
	}
	if err := Remove(ctx, root, registered, RemoveOptions{}); err != nil {
		t.Fatalf("remove registered: %v", err)
	}
	if _, err := os.Stat(registered); !os.IsNotExist(err) {
		t.Fatalf("registered worktree still exists or stat failed unexpectedly: %v", err)
	}

	orphan := filepath.Join(root, ".claude", "worktrees", "agent-orphan")
	if err := os.MkdirAll(orphan, 0o755); err != nil {
		t.Fatal(err)
	}
	if err := Remove(ctx, root, orphan, RemoveOptions{Force: true}); err != nil {
		t.Fatalf("remove orphan: %v", err)
	}
	if _, err := os.Stat(orphan); !os.IsNotExist(err) {
		t.Fatalf("orphan worktree still exists or stat failed unexpectedly: %v", err)
	}
}

func initRepo(t *testing.T) string {
	t.Helper()
	root := t.TempDir()
	git(t, root, "init")
	git(t, root, "config", "user.email", "test@example.com")
	git(t, root, "config", "user.name", "Test User")
	if err := os.MkdirAll(filepath.Join(root, ".ddx"), 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(filepath.Join(root, "README.md"), []byte("fixture\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	git(t, root, "add", "README.md")
	git(t, root, "commit", "-m", "init")
	return root
}

func addWorktree(t *testing.T, root, name string) string {
	t.Helper()
	path := filepath.Join(root, ".claude", "worktrees", "agent-"+name)
	git(t, root, "worktree", "add", "--detach", path, "HEAD")
	return path
}

func commitInWorktree(t *testing.T, path, file string) string {
	t.Helper()
	if err := os.WriteFile(filepath.Join(path, file), []byte("done\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	git(t, path, "add", file)
	git(t, path, "commit", "-m", "done")
	return git(t, path, "rev-parse", "HEAD")
}

func writeBundle(t *testing.T, root, attempt, bead, base, result, wt string, created, finished time.Time) {
	t.Helper()
	dir := filepath.Join(root, ".ddx", "executions", attempt)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		t.Fatal(err)
	}
	manifest := map[string]any{
		"attempt_id": attempt,
		"bead_id":    bead,
		"base_rev":   base,
		"created_at": created.Format(time.RFC3339),
		"paths": map[string]any{
			"worktree": wt,
		},
	}
	writeJSON(t, filepath.Join(dir, "manifest.json"), manifest)
	if result != "" || !finished.IsZero() {
		writeJSON(t, filepath.Join(dir, "result.json"), map[string]any{
			"attempt_id":  attempt,
			"bead_id":     bead,
			"base_rev":    base,
			"result_rev":  result,
			"outcome":     "merged",
			"status":      "success",
			"finished_at": finished.Format(time.RFC3339),
		})
	}
}

func writeJSON(t *testing.T, path string, value any) {
	t.Helper()
	data, err := json.MarshalIndent(value, "", "  ")
	if err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(path, append(data, '\n'), 0o644); err != nil {
		t.Fatal(err)
	}
}

func git(t *testing.T, dir string, args ...string) string {
	t.Helper()
	cmd := exec.Command("git", append([]string{"-C", dir}, args...)...)
	out, err := cmd.CombinedOutput()
	if err != nil {
		t.Fatalf("git %v failed: %s: %v", args, out, err)
	}
	return stringsTrim(string(out))
}

func stringsTrim(s string) string {
	return strings.TrimSpace(s)
}

func assertState(t *testing.T, states map[string]string, key, want string) {
	t.Helper()
	if got := states[key]; got != want {
		t.Fatalf("%s state = %q, want %q (all states: %#v)", key, got, want, states)
	}
}

package worktrees

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
