const (
	StateActive    = "active"
	StateCompleted = "completed"
	StateAbandoned = "abandoned"
	StateOrphan    = "orphan"

	DefaultAbandonedAfter = 24 * time.Hour
	DefaultSweepInterval  = 15 * time.Minute
)

type ActiveAttempt struct {
	AttemptID string
	BeadID    string
}

type Policy struct {
	AbandonedAfter time.Duration
	AutoPrune      bool
	SweepInterval  time.Duration
}

func (p Policy) WithDefaults() Policy {
	if p.AbandonedAfter <= 0 {
		p.AbandonedAfter = DefaultAbandonedAfter
	}
	if p.SweepInterval <= 0 {
		p.SweepInterval = DefaultSweepInterval
	}
	return p
}

type Entry struct {
	Path           string
	Branch         string
	BeadID         string
	ExecutionID    string
	BaseRev        string
	HeadRev        string
	ResultRev      string
	State          string
	CreatedAt      time.Time
	LastActivityAt time.Time
	DiskBytes      int64
	Registered     bool
	FSExists       bool
}

type Counters struct {
	Total     int
	Active    int
	Completed int
	Abandoned int
	Orphan    int
}

type ClassificationInput struct {
	Registered     bool
	FSExists       bool
	Running        bool
	HasVerdict     bool
	HeadRev        string
	ResultRev      string
	LastActivityAt time.Time
	Now            time.Time
	AbandonedAfter time.Duration
}

func Classify(in ClassificationInput) string {
	if !in.Registered || !in.FSExists {
		return StateOrphan
	}
	if in.Running {
		return StateActive
	}
	if in.HasVerdict && in.ResultRev != "" && in.HeadRev == in.ResultRev {
		return StateCompleted
	}
	after := in.AbandonedAfter
	if after <= 0 {
		after = DefaultAbandonedAfter
	}
	now := in.Now
	if now.IsZero() {
		now = time.Now().UTC()
	}
	if !in.LastActivityAt.IsZero() && in.LastActivityAt.Before(now.Add(-after)) {
		return StateAbandoned
	}
	return StateActive
}

type InventoryOptions struct {
	Now            time.Time
	AbandonedAfter time.Duration
	ActiveAttempts []ActiveAttempt
}

type gitWorktree struct {
	Path       string
	Head       string
	Branch     string
	Prunable   bool
	Porcelain  map[string]string
	Registered bool
}

type executionBundle struct {
	AttemptID  string
	WorkerID   string
	BeadID     string
	BaseRev    string
	CreatedAt  time.Time
	Worktree   string
	ResultRev  string
	FinishedAt time.Time
	Outcome    string
	Status     string
	ResultPath string
}

func List(ctx context.Context, projectRoot string, opts InventoryOptions) ([]Entry, error) {
	projectRoot = cleanPath(projectRoot)
	if projectRoot == "" {
		return nil, fmt.Errorf("project root is required")
	}
	now := opts.Now
	if now.IsZero() {
		now = time.Now().UTC()
	}
	abandonedAfter := opts.AbandonedAfter
	if abandonedAfter <= 0 {
		abandonedAfter = DefaultAbandonedAfter
	}

	registered, err := gitWorktreeList(ctx, projectRoot)
	if err != nil {
		return nil, err
	}
	bundles := readExecutionBundles(projectRoot)
	bundlesByPath, bundlesByAttempt := indexBundles(projectRoot, bundles)
	active := activeAttemptSet(opts.ActiveAttempts)

	seen := map[string]bool{}
	var out []Entry
	for _, wt := range registered {
		path := cleanPath(wt.Path)
		if path == "" || samePath(path, projectRoot) {
			continue
		}
		if !looksManaged(path, wt.Branch) && bundleForPath(path, bundlesByPath, bundlesByAttempt) == nil {
			continue
		}
		entry := entryFromGitWorktree(ctx, projectRoot, wt, bundlesByPath, bundlesByAttempt, active, now, abandonedAfter)
		out = append(out, entry)
		seen[path] = true
	}

	for _, path := range discoverDiskCandidates(projectRoot, bundles) {
		path = cleanPath(path)
		if path == "" || seen[path] {
			continue
		}
		if bundleForPath(path, bundlesByPath, bundlesByAttempt) == nil && !underProjectManagedRoot(projectRoot, path) && !sameRepo(projectRoot, path) {
			continue
		}
		entry := entryFromDiskPath(ctx, path, bundlesByPath, bundlesByAttempt, active, now, abandonedAfter)
		out = append(out, entry)
		seen[path] = true
	}

	sort.SliceStable(out, func(i, j int) bool {
		if !out[i].LastActivityAt.Equal(out[j].LastActivityAt) {
			return out[i].LastActivityAt.After(out[j].LastActivityAt)
		}
		return out[i].Path < out[j].Path
	})
	return out, nil
}

func Count(entries []Entry) Counters {
	var c Counters
	c.Total = len(entries)
	for _, e := range entries {
		switch e.State {
		case StateActive:
			c.Active++
		case StateCompleted:
			c.Completed++
		case StateAbandoned:
			c.Abandoned++
		case StateOrphan:
			c.Orphan++
		}
	}
	return c
}

type RemoveOptions struct {
	Force bool
}

func Remove(ctx context.Context, projectRoot, path string, opts RemoveOptions) error {
	projectRoot = cleanPath(projectRoot)
	path = cleanPath(path)
	if projectRoot == "" || path == "" {
		return fmt.Errorf("project root and worktree path are required")
	}
	entries, err := List(ctx, projectRoot, InventoryOptions{})
	if err != nil {
		return err
	}
	var target *Entry
	for i := range entries {
		if samePath(entries[i].Path, path) {
			target = &entries[i]
			break
		}
	}
	if target == nil {
		return fmt.Errorf("worktree %q not found", path)
	}
	if target.State == StateActive && !opts.Force {
		return fmt.Errorf("worktree %q is active; stop the worker before removing it", path)
	}
	if target.Registered {
		args := []string{"-C", projectRoot, "worktree", "remove"}
		if opts.Force || target.State == StateOrphan {
			args = append(args, "--force")
		}
		args = append(args, path)
		out, err := exec.CommandContext(ctx, "git", args...).CombinedOutput()
		if err != nil {
			return fmt.Errorf("git worktree remove: %s: %w", strings.TrimSpace(string(out)), err)
		}
	} else if opts.Force || target.State == StateOrphan || target.State == StateAbandoned {
		if err := os.RemoveAll(path); err != nil {
			return fmt.Errorf("remove orphan worktree directory: %w", err)
		}
	} else {
		return fmt.Errorf("worktree %q is not registered; force removal is required", path)
	}
	_ = exec.CommandContext(ctx, "git", "-C", projectRoot, "worktree", "prune").Run()
	return nil
}

