func Prunable(entries []Entry) []Entry {
	var out []Entry
	for _, e := range entries {
		if e.State == StateAbandoned || e.State == StateOrphan {
			out = append(out, e)
		}
	}
	return out
}

func gitWorktreeList(ctx context.Context, projectRoot string) ([]gitWorktree, error) {
	out, err := exec.CommandContext(ctx, "git", "-C", projectRoot, "worktree", "list", "--porcelain").Output()
	if err != nil {
		return nil, fmt.Errorf("git worktree list: %w", err)
	}
	var worktrees []gitWorktree
	var current *gitWorktree
	scanner := bufio.NewScanner(strings.NewReader(string(out)))
	for scanner.Scan() {
		line := scanner.Text()
		if line == "" {
			continue
		}
		key, value, ok := strings.Cut(line, " ")
		if !ok {
			key = line
			value = "true"
		}
		if key == "worktree" {
			if current != nil {
				worktrees = append(worktrees, *current)
			}
			current = &gitWorktree{Path: value, Registered: true, Porcelain: map[string]string{}}
			continue
		}
		if current == nil {
			continue
		}
		current.Porcelain[key] = value
		switch key {
		case "HEAD":
			current.Head = value
		case "branch":
			current.Branch = strings.TrimPrefix(value, "refs/heads/")
		case "prunable":
			current.Prunable = true
		}
	}
	if current != nil {
		worktrees = append(worktrees, *current)
	}
	return worktrees, scanner.Err()
}

func entryFromGitWorktree(ctx context.Context, projectRoot string, wt gitWorktree, byPath map[string]*executionBundle, byAttempt map[string]*executionBundle, active map[string]bool, now time.Time, abandonedAfter time.Duration) Entry {
	path := cleanPath(wt.Path)
	info, statErr := os.Stat(path)
	fsExists := statErr == nil && info.IsDir()
	bundle := bundleForPath(path, byPath, byAttempt)
	entry := Entry{Path: path, Branch: wt.Branch, HeadRev: wt.Head, Registered: true, FSExists: fsExists}
	if entry.HeadRev == "" && fsExists {
		entry.HeadRev = headRev(ctx, path)
	}
	applyBundle(&entry, bundle)
	fillTimesAndSize(&entry, info)
	running := entryRunning(entry, active)
	entry.State = Classify(ClassificationInput{
		Registered:     entry.Registered,
		FSExists:       entry.FSExists,
		Running:        running,
		HasVerdict:     bundle != nil && (bundle.Outcome != "" || bundle.Status != "" || !bundle.FinishedAt.IsZero()),
		HeadRev:        entry.HeadRev,
		ResultRev:      entry.ResultRev,
		LastActivityAt: entry.LastActivityAt,
		Now:            now,
		AbandonedAfter: abandonedAfter,
	})
	return entry
}

func entryFromDiskPath(ctx context.Context, path string, byPath map[string]*executionBundle, byAttempt map[string]*executionBundle, active map[string]bool, now time.Time, abandonedAfter time.Duration) Entry {
	info, statErr := os.Stat(path)
	fsExists := statErr == nil && info.IsDir()
	bundle := bundleForPath(path, byPath, byAttempt)
	entry := Entry{Path: path, Registered: false, FSExists: fsExists}
	if fsExists && hasGitMetadata(path) {
		entry.HeadRev = headRev(ctx, path)
		entry.Branch = branchName(ctx, path)
	}
	applyBundle(&entry, bundle)
	fillTimesAndSize(&entry, info)
	running := entryRunning(entry, active)
	entry.State = Classify(ClassificationInput{
		Registered:     entry.Registered,
		FSExists:       entry.FSExists,
		Running:        running,
		HasVerdict:     bundle != nil && (bundle.Outcome != "" || bundle.Status != "" || !bundle.FinishedAt.IsZero()),
		HeadRev:        entry.HeadRev,
		ResultRev:      entry.ResultRev,
		LastActivityAt: entry.LastActivityAt,
		Now:            now,
		AbandonedAfter: abandonedAfter,
	})
	return entry
}

func applyBundle(entry *Entry, bundle *executionBundle) {
	if bundle == nil {
		if bead, attempt := parseExecuteBeadPath(entry.Path); bead != "" {
			entry.BeadID = bead
			entry.ExecutionID = attempt
		}
		return
	}
	entry.BeadID = bundle.BeadID
	entry.ExecutionID = bundle.AttemptID
	entry.BaseRev = bundle.BaseRev
	entry.ResultRev = bundle.ResultRev
	if entry.CreatedAt.IsZero() {
		entry.CreatedAt = bundle.CreatedAt
	}
	if bundle.FinishedAt.After(entry.LastActivityAt) {
		entry.LastActivityAt = bundle.FinishedAt
	}
}

func fillTimesAndSize(entry *Entry, info fs.FileInfo) {
	if info != nil {
		if entry.CreatedAt.IsZero() {
			entry.CreatedAt = info.ModTime()
		}
		if info.ModTime().After(entry.LastActivityAt) {
			entry.LastActivityAt = info.ModTime()
		}
		entry.DiskBytes = dirSize(entry.Path)
	}
	if entry.LastActivityAt.IsZero() {
		entry.LastActivityAt = entry.CreatedAt
	}
}

func entryRunning(entry Entry, active map[string]bool) bool {
	if entry.ExecutionID != "" && active["attempt:"+entry.ExecutionID] {
		return true
	}
	if entry.BeadID != "" && active["bead:"+entry.BeadID] {
		return true
	}
	return false
}

func activeAttemptSet(attempts []ActiveAttempt) map[string]bool {
	out := map[string]bool{}
	for _, a := range attempts {
		if a.AttemptID != "" {
			out["attempt:"+a.AttemptID] = true
		}
		if a.BeadID != "" {
			out["bead:"+a.BeadID] = true
		}
	}
	return out
}

func readExecutionBundles(projectRoot string) []executionBundle {
	root := filepath.Join(projectRoot, ".ddx", "executions")
	entries, err := os.ReadDir(root)
	if err != nil {
		return nil
	}
	var out []executionBundle
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		dir := filepath.Join(root, entry.Name())
		bundle := readExecutionBundle(dir)
		if bundle.AttemptID == "" {
			bundle.AttemptID = entry.Name()
		}
		if bundle.AttemptID != "" {
			out = append(out, bundle)
		}
	}
	return out
}

func readExecutionBundle(dir string) executionBundle {
	var bundle executionBundle
	manifestData, err := os.ReadFile(filepath.Join(dir, "manifest.json"))
	if err == nil {
		var m struct {
			AttemptID string    `json:"attempt_id"`
			WorkerID  string    `json:"worker_id"`
			BeadID    string    `json:"bead_id"`
			BaseRev   string    `json:"base_rev"`
			CreatedAt time.Time `json:"created_at"`
			Paths     struct {
				Worktree string `json:"worktree"`
			} `json:"paths"`
		}
		if json.Unmarshal(manifestData, &m) == nil {
			bundle.AttemptID = m.AttemptID
			bundle.WorkerID = m.WorkerID
			bundle.BeadID = m.BeadID
			bundle.BaseRev = m.BaseRev
			bundle.CreatedAt = m.CreatedAt
			bundle.Worktree = m.Paths.Worktree
		}
	}
	resultPath := filepath.Join(dir, "result.json")
	resultData, err := os.ReadFile(resultPath)
	if err == nil {
		var r struct {
			BeadID     string    `json:"bead_id"`
			AttemptID  string    `json:"attempt_id"`
			BaseRev    string    `json:"base_rev"`
			ResultRev  string    `json:"result_rev"`
			Outcome    string    `json:"outcome"`
			Status     string    `json:"status"`
			FinishedAt time.Time `json:"finished_at"`
		}
		if json.Unmarshal(resultData, &r) == nil {
			if bundle.AttemptID == "" {
				bundle.AttemptID = r.AttemptID
			}
			if bundle.BeadID == "" {
				bundle.BeadID = r.BeadID
			}
			if bundle.BaseRev == "" {
				bundle.BaseRev = r.BaseRev
			}
			bundle.ResultRev = r.ResultRev
			bundle.Outcome = r.Outcome
			bundle.Status = r.Status
			bundle.FinishedAt = r.FinishedAt
			bundle.ResultPath = resultPath
		}
	}
	return bundle
}

func indexBundles(projectRoot string, bundles []executionBundle) (map[string]*executionBundle, map[string]*executionBundle) {
	byPath := map[string]*executionBundle{}
	byAttempt := map[string]*executionBundle{}
	for i := range bundles {
		b := &bundles[i]
		if b.AttemptID != "" {
			byAttempt[b.AttemptID] = b
		}
		for _, path := range possibleBundlePaths(projectRoot, *b) {
			if path != "" {
				byPath[cleanPath(path)] = b
			}
		}
	}
	return byPath, byAttempt
}

func possibleBundlePaths(projectRoot string, b executionBundle) []string {
	var paths []string
	if b.Worktree != "" {
		if filepath.IsAbs(b.Worktree) {
			paths = append(paths, b.Worktree)
		} else {
			paths = append(paths, filepath.Join(projectRoot, filepath.FromSlash(b.Worktree)))
			if strings.HasPrefix(b.Worktree, "tmp/") || strings.HasPrefix(b.Worktree, "private/tmp/") || strings.HasPrefix(b.Worktree, "var/folders/") {
				paths = append(paths, string(filepath.Separator)+filepath.FromSlash(b.Worktree))
			}
		}
	}
	if b.BeadID != "" && b.AttemptID != "" {
		base := os.Getenv("DDX_EXEC_WT_DIR")
		if base == "" {
			base = filepath.Join(os.TempDir(), "ddx-exec-wt")
		}
		paths = append(paths, filepath.Join(base, ".execute-bead-wt-"+b.BeadID+"-"+b.AttemptID))
	}
	return paths
}

func bundleForPath(path string, byPath map[string]*executionBundle, byAttempt map[string]*executionBundle) *executionBundle {
	if b := byPath[cleanPath(path)]; b != nil {
		return b
	}
	_, attempt := parseExecuteBeadPath(path)
	if attempt != "" {
		return byAttempt[attempt]
	}
	return nil
}

func discoverDiskCandidates(projectRoot string, bundles []executionBundle) []string {
	seen := map[string]bool{}
	add := func(path string) {
		path = cleanPath(path)
		if path != "" {
			seen[path] = true
		}
	}
	for _, b := range bundles {
		for _, path := range possibleBundlePaths(projectRoot, b) {
			if info, err := os.Stat(path); err == nil && info.IsDir() {
				add(path)
			}
		}
	}
	for _, root := range []string{
		filepath.Join(projectRoot, ".claude", "worktrees"),
		filepath.Join(projectRoot, ".ddx", "worktrees"),
	} {
		entries, err := os.ReadDir(root)
		if err != nil {
			continue
		}
		for _, entry := range entries {
			if !entry.IsDir() {
				continue
			}
			name := entry.Name()
			if strings.HasPrefix(name, "agent-") || strings.HasPrefix(name, ".execute-bead-wt-") || strings.HasPrefix(name, "ddx-") {
				add(filepath.Join(root, name))
			}
		}
	}
	out := make([]string, 0, len(seen))
	for path := range seen {
		out = append(out, path)
	}
	sort.Strings(out)
	return out
}

func looksManaged(path, branch string) bool {
	base := filepath.Base(path)
	return strings.Contains(path, string(filepath.Separator)+".claude"+string(filepath.Separator)+"worktrees"+string(filepath.Separator)) ||
		strings.Contains(path, string(filepath.Separator)+".ddx"+string(filepath.Separator)+"worktrees"+string(filepath.Separator)) ||
		strings.Contains(path, string(filepath.Separator)+"ddx-exec-wt"+string(filepath.Separator)+".execute-bead-wt-") ||
		strings.HasPrefix(base, ".execute-bead-wt-") ||
		strings.HasPrefix(branch, "worktree-agent-")
}

func underProjectManagedRoot(projectRoot, path string) bool {
	for _, root := range []string{filepath.Join(projectRoot, ".claude", "worktrees"), filepath.Join(projectRoot, ".ddx", "worktrees")} {
		rel, err := filepath.Rel(root, path)
		if err == nil && rel != "." && !strings.HasPrefix(rel, ".."+string(filepath.Separator)) && rel != ".." {
			return true
		}
	}
	return false
}

func parseExecuteBeadPath(path string) (string, string) {
	base := filepath.Base(path)
	if !strings.HasPrefix(base, ".execute-bead-wt-") {
		return "", ""
	}
	rest := strings.TrimPrefix(base, ".execute-bead-wt-")
	idx := strings.Index(rest, "-20")
	if idx <= 0 {
		return "", ""
	}
	return rest[:idx], rest[idx+1:]
}

func sameRepo(projectRoot, path string) bool {
	commonRoot := gitCommonDir(projectRoot)
	if commonRoot == "" {
		return false
	}
	commonPath := gitCommonDir(path)
	return commonPath != "" && samePath(commonRoot, commonPath)
}

func gitCommonDir(path string) string {
	out, err := exec.Command("git", "-C", path, "rev-parse", "--git-common-dir").Output()
	if err != nil {
		return ""
	}
	common := strings.TrimSpace(string(out))
	if common == "" {
		return ""
	}
	if filepath.IsAbs(common) {
		return cleanPath(common)
	}
	return cleanPath(filepath.Join(path, common))
}

func hasGitMetadata(path string) bool {
	_, err := os.Stat(filepath.Join(path, ".git"))
	return err == nil
}

func headRev(ctx context.Context, path string) string {
	out, err := exec.CommandContext(ctx, "git", "-C", path, "rev-parse", "HEAD").Output()
	if err != nil {
		return ""
	}
	return strings.TrimSpace(string(out))
}

func branchName(ctx context.Context, path string) string {
	out, err := exec.CommandContext(ctx, "git", "-C", path, "branch", "--show-current").Output()
	if err != nil {
		return ""
	}
	return strings.TrimSpace(string(out))
}

func dirSize(path string) int64 {
	var total int64
	_ = filepath.WalkDir(path, func(_ string, d fs.DirEntry, err error) error {
		if err != nil || d.IsDir() {
			return nil
		}
		info, err := d.Info()
		if err == nil {
			total += info.Size()
		}
		return nil
	})
	return total
}

func cleanPath(path string) string {
	if path == "" {
		return ""
	}
	abs, err := filepath.Abs(path)
	if err == nil {
		path = abs
	}
	if resolved, err := filepath.EvalSymlinks(path); err == nil {
		path = resolved
	}
	return filepath.Clean(path)
}

func samePath(a, b string) bool {
	return cleanPath(a) == cleanPath(b)
}
